import React, { useContext } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import {
  Drawer,
  AppBar,
  Toolbar,
  Typography,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Button,
  Box,
} from '@mui/material';
import DashboardIcon from '@mui/icons-material/Dashboard';
import PointOfSaleIcon from '@mui/icons-material/PointOfSale';
import LogoutIcon from '@mui/icons-material/Logout';
import { AuthContext } from '../context/AuthContext';

const drawerWidth = 240;

export default function AdminLayout() {
  const { logout, user } = useContext(AuthContext);
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const menuItems = [
    { text: 'HQ Dashboard', icon: <DashboardIcon />, path: '/hq-dashboard' },
    { text: 'POS Terminal', icon: <PointOfSaleIcon />, path: '/pos' },
  ];

  return (
    <Box sx={{ display: 'flex' }} className="bg-gray-50 min-h-screen">
      {/* Topbar */}
      <AppBar
        position="fixed"
        sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}
      >
        <Toolbar className="justify-between">
          <Typography variant="h6" noWrap component="div">
            Central POS System
          </Typography>
          <div className="flex items-center gap-4">
            <Typography variant="body2">Hello, {user?.name}</Typography>
            <Button
              color="inherit"
              onClick={handleLogout}
              startIcon={<LogoutIcon />}
            >
              Logout
            </Button>
          </div>
        </Toolbar>
      </AppBar>

      {/* Sidebar */}
      <Drawer
        variant="permanent"
        sx={{
          width: drawerWidth,
          flexShrink: 0,
          [`& .MuiDrawer-paper`]: {
            width: drawerWidth,
            boxSizing: 'border-box',
          },
        }}
      >
        <Toolbar /> {/* Topbar এর নিচে জায়গা রাখার জন্য */}
        <Box sx={{ overflow: 'auto' }}>
          <List>
            {menuItems.map((item) => (
              <ListItem
                button
                key={item.text}
                onClick={() => navigate(item.path)}
                selected={location.pathname === item.path}
                className={location.pathname === item.path ? 'bg-blue-50' : ''}
              >
                <ListItemIcon
                  className={
                    location.pathname === item.path ? 'text-blue-600' : ''
                  }
                >
                  {item.icon}
                </ListItemIcon>
                <ListItemText primary={item.text} />
              </ListItem>
            ))}
          </List>
        </Box>
      </Drawer>

      {/* Main Content Area */}
      <Box component="main" sx={{ flexGrow: 1, p: 3 }}>
        <Toolbar /> {/* Topbar এর নিচে জায়গা রাখার জন্য */}
        <Outlet /> {/* এখানেই HQDashboard বা POS রেন্ডার হবে */}
      </Box>
    </Box>
  );
}
